import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const BiometricLogin = ({ navigation }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const biometric = new ReactNativeBiometrics();

  useEffect(() => {
    checkAuthenticationStatus();
  }, []);

  const checkAuthenticationStatus = async () => {
    try {
      const authStatus = await AsyncStorage.getItem('authenticated');
      if (authStatus === 'true') {
        navigation.navigate('Home');
      }
    } catch (error) {
      console.error('Error checking authentication status:', error);
    }
  };

  const authenticate = async () => {
    biometric.isSensorAvailable().then((resultObject) => {
      const { available, reason } = resultObject;

      if (available && reason === ReactNativeBiometrics.BIOMETRIC_SUCCESS) {
        biometric.simplePrompt({ promptMessage: 'Sign in with Face ID or fingerprint' })
          .then((resultObject) => {
            const { success } = resultObject;

            if (success) {
              setIsAuthenticated(true);
              AsyncStorage.setItem('authenticated', 'true')
                .then(() => navigation.navigate('Home'))
                .catch((error) => console.error('Error storing authentication status:', error));
            }
          })
          .catch((error) => console.error('Biometric authentication failed:', error));
      } else {
        Alert.alert('Biometrics not available', reason);
        // Fallback to password login
        navigation.navigate('PasswordLogin');
      }
    });
  };

  return (
    <View>
      {isAuthenticated ? (
        <Text>Authenticated</Text>
      ) : (
        <Button title="Authenticate" onPress={authenticate} />
      )}
    </View>
  );
};

export default BiometricLogin;